{
  "version": "1.0",
  "sources": {
    "vehicle_iobe": {
      "file": "schema_vehicle_iobe.json",
      "description": "车辆内外部边界（IoBE）数据模型，定义车辆网络安全边界与暴露面信息。",
      "category": "vehicle",
      "storage": "neo4j"
    },
    "tara": {
      "file": "schema_tara.json",
      "description": "TARA（威胁分析与风险评估）图数据库 Schema，包含车辆组件、资产、损害场景、威胁场景、漏洞、攻击路径、攻击可行性、风险评估、安全目标、安全声明、安全需求及其关系定义，符合 STIX 2.1 标准。",
      "category": "threat_analysis",
      "storage": "neo4j"
    },
    "ses": {
      "file": "schema_ses.json",
      "description": "网络安全需求（SES）Schema，适配密码算法与安全需求类数据，包含安全目标、消减措施、关键词标签等，符合 STIX 2.1 + MongoDB 存储标准。",
      "category": "security_requirement",
      "storage": "mongodb"
    },
    "vehicle_func": {
      "file": "schema_vehicle_func.json",
      "description": "车辆功能 Schema，定义车辆功能数据模型，包含功能 ID、名称、描述及关联 ECU 列表，符合 STIX 2.1 标准。",
      "category": "vehicle",
      "storage": "neo4j"
    },
    "ecu_func": {
      "file": "schema_ecu_func.json",
      "description": "ECU 控制器 Schema，定义 ECU 控制器数据模型，包含 ECU 名称及相关功能列表，符合 STIX 2.1 标准。",
      "category": "vehicle",
      "storage": "neo4j"
    },
    "func_design_spec": {
      "file": "schema_func_design_spec.json",
      "description": "功能设计规格 Schema，定义 MDC Core 功能设计规格文档结构，涵盖网络安全、哨兵模式、启动/OS、AI 框架、CAN 通信、MCU、CI/CD 等功能需求。",
      "category": "design_spec",
      "storage": "neo4j"
    },
    "cve2oss": {
      "file": "schema_cve2oss.json",
      "description": "CVE2OSS 漏洞查询代理服务，通过 W3 SSO 认证获取 Token 后并发查询 REPAIRED_STATUS 和 PRECAUTION_STATUS，合并结果并过滤返回 CVEID/PROD_CN_NAME/EDITION_CODE/LDY_NAME/HWPSIRTID 字段。",
      "category": "proxy",
      "storage": "proxy"
    },
    "opencti": {
      "file": "STIX_schema",
      "description": "OpenCTI 威胁情报源的 STIX 2.1 Schema 聚合目录，API Center 会从 schema/STIX_schema 聚合返回可消费的 schema 结构，并将查询路由到外部 OpenCTI GraphQL 接口。",
      "category": "threat_intelligence",
      "storage": "opencti"
    }
  }
}
"
}
]
