"id": "{0A7EC7DC-053C-4b52-9A26-03C85D9D40B3}",
"name": "cve2oss"
,"type": "ArchiMate_DataObject"
,"browser_path": "Model/System/ApplicationLayer/ApplicationLayer/cve2oss"
,"attributes": [
{
"name": "SCHEMA",
"content": "Relative File Path:D:\\Projects\\AI4X-Platform\\schema\\schema_cve2oss.json

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "CVE2OSS API Schema",
  "description": "CVE2OSS 漏洞查询代理服务 Schema，通过 W3 SSO 认证获取 Token 后并发查询 REPAIRED_STATUS 和 PRECAUTION_STATUS，合并结果并过滤返回白名单字段。",
  "type": "object",
  "properties": {
    "endpoints": {
      "type": "object",
      "description": "CVE2OSS API 端点定义",
      "properties": {
        "query": {
          "type": "object",
          "title": "CVE2OSS 漏洞查询",
          "description": "POST /api/v1/cve2oss/query — 输入 CVE ID 和 PBI 号，系统自动获取 W3 Token 并向上游发起 REPAIRED_STATUS 和 PRECAUTION_STATUS 两次查询，合并结果后仅返回白名单字段。",
          "properties": {
            "method": { "const": "POST" },
            "path": { "const": "/api/v1/cve2oss/query" },
            "request": {
              "type": "object",
              "title": "查询请求体",
              "properties": {
                "cve_id": {
                  "type": "string",
                  "description": "CVE 编号（必填）",
                  "examples": ["CVE-2023-53368"]
                },
                "sub_id": {
                  "type": "string",
                  "description": "C版本 PBI 号（必填）",
                  "examples": ["260928142"]
                },
                "repaired_overrides": {
                  "type": ["object", "null"],
                  "description": "可选：覆盖 REPAIRED_STATUS 请求体中的默认字段。传入的字段会覆盖下方默认值中的同名字段。",
                  "default": null,
                  "examples": [
                    { "pageSize": 100, "startTime": "202301" },
                    { "pageSize": 200, "handlePriority": ["ONE", "TWO"] },
                    { "vulTypeEnums": ["OPEN_SOURCE"], "isOverview": true }
                  ],
                  "properties": {
                    "tabEnums": {
                      "type": "string",
                      "description": "查询类型标识（默认 REPAIRED_STATUS，一般不需要覆盖）",
                      "default": "REPAIRED_STATUS"
                    },
                    "handlePriority": {
                      "type": "array",
                      "description": "处理优先级过滤",
                      "default": ["ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX"],
                      "items": { "type": "string", "enum": ["ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX"] }
                    },
                    "vulTypeEnums": {
                      "type": "array",
                      "description": "漏洞类型过滤",
                      "default": ["OPEN_SOURCE", "THIRD_PARTY", "HARDWARE", "SELF_DEVELOPED"],
                      "items": { "type": "string", "enum": ["OPEN_SOURCE", "THIRD_PARTY", "HARDWARE", "SELF_DEVELOPED"] }
                    },
                    "depCnName": {
                      "type": "string",
                      "description": "部门中文名称过滤",
                      "default": ""
                    },
                    "deptId": {
                      "type": "string",
                      "description": "部门 ID 过滤",
                      "default": ""
                    },
                    "versionName": {
                      "type": "string",
                      "description": "版本名称过滤",
                      "default": ""
                    },
                    "isOverview": {
                      "type": "boolean",
                      "description": "是否返回概览",
                      "default": false
                    },
                    "isVersionDetail": {
                      "type": "boolean",
                      "description": "是否返回版本详情",
                      "default": false
                    },
                    "isTotalPatchSlo": {
                      "type": "boolean",
                      "description": "是否包含总补丁 SLO",
                      "default": true
                    },
                    "isSloAchieved": {
                      "type": "boolean",
                      "description": "是否仅返回已达成 SLO 的记录",
                      "default": false
                    },
                    "isExtra": {
                      "type": "boolean",
                      "description": "是否包含额外信息",
                      "default": false
                    },
                    "startTime": {
                      "type": "string",
                      "description": "查询起始时间（格式 YYYYMM）",
                      "default": "190011"
                    },
                    "endTime": {
                      "type": "string",
                      "description": "查询结束时间（格式 YYYYMM，留空则自动填充当前年月）",
                      "default": ""
                    },
                    "pageNum": {
                      "type": "integer",
                      "description": "页码",
                      "default": 1
                    },
                    "pageSize": {
                      "type": "integer",
                      "description": "每页记录数",
                      "default": 5000
                    }
                  }
                },
                "precaution_overrides": {
                  "type": ["object", "null"],
                  "description": "可选：覆盖 PRECAUTION_STATUS 请求体中的默认字段。传入的字段会覆盖下方默认值中的同名字段。",
                  "default": null,
                  "examples": [
                    { "pageSize": 100 },
                    { "preCautionEnums": "EXPIRED_TOTAL", "pageSize": 200 },
                    { "vulTypeEnums": ["OPEN_SOURCE", "THIRD_PARTY"], "startTime": "202301" }
                  ],
                  "properties": {
                    "tabEnums": {
                      "type": "string",
                      "description": "查询类型标识（默认 PRECAUTION_STATUS，一般不需要覆盖）",
                      "default": "PRECAUTION_STATUS"
                    },
                    "handlePriority": {
                      "type": "array",
                      "description": "处理优先级过滤",
                      "default": ["ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX"],
                      "items": { "type": "string", "enum": ["ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX"] }
                    },
                    "vulTypeEnums": {
                      "type": "array",
                      "description": "漏洞类型过滤",
                      "default": ["OPEN_SOURCE", "THIRD_PARTY", "HARDWARE", "SELF_DEVELOPED"],
                      "items": { "type": "string", "enum": ["OPEN_SOURCE", "THIRD_PARTY", "HARDWARE", "SELF_DEVELOPED"] }
                    },
                    "depCnName": {
                      "type": "string",
                      "description": "部门中文名称过滤",
                      "default": ""
                    },
                    "deptId": {
                      "type": "string",
                      "description": "部门 ID 过滤",
                      "default": ""
                    },
                    "versionName": {
                      "type": "string",
                      "description": "版本名称过滤",
                      "default": ""
                    },
                    "isOverview": {
                      "type": "boolean",
                      "description": "是否返回概览",
                      "default": false
                    },
                    "isVersionDetail": {
                      "type": "boolean",
                      "description": "是否返回版本详情",
                      "default": false
                    },
                    "isTotalPatchSlo": {
                      "type": "boolean",
                      "description": "是否包含总补丁 SLO",
                      "default": true
                    },
                    "isSloAchieved": {
                      "type": "boolean",
                      "description": "是否仅返回已达成 SLO 的记录",
                      "default": false
                    },
                    "isExtra": {
                      "type": "boolean",
                      "description": "是否包含额外信息",
                      "default": false
                    },
                    "startTime": {
                      "type": "string",
                      "description": "查询起始时间（格式 YYYYMM）",
                      "default": "190011"
                    },
                    "endTime": {
                      "type": "string",
                      "description": "查询结束时间（格式 YYYYMM，留空则自动填充当前年月）",
                      "default": ""
                    },
                    "preCautionEnums": {
                      "type": "string",
                      "description": "预防状态枚举（PRECAUTION_STATUS 专有字段）",
                      "default": "TAL"
                    },
                    "pageNum": {
                      "type": "integer",
                      "description": "页码",
                      "default": 1
                    },
                    "pageSize": {
                      "type": "integer",
                      "description": "每页记录数",
                      "default": 5000
                    }
                  }
